class SecureModelLoader:
    def __init__(self, trusted_hashes_file: Optional[str] = None):
        self.trusted_hashes = {}
        if trusted_hashes_file and os.path.exists(trusted_hashes_file):
            with open(trusted_hashes_file, 'r') as f:
                self.trusted_hashes = json.load(f)
    
    def compute_hash(self, file_path: str, algorithm: str = 'sha256') -> str:
        hash_func = hashlib.new(algorithm)
        with open(file_path, 'rb') as f:
            for chunk in iter(lambda: f.read(4096), b''):
                hash_func.update(chunk)
        return hash_func.hexdigest()
    
    def verify_hash(self, file_path: str, expected_hash: str, algorithm: str = 'sha256') -> bool:
        computed_hash = self.compute_hash(file_path, algorithm)
        return computed_hash == expected_hash
    
    def download_model(self, url: str, save_path: str, expected_hash: Optional[str] = None) -> str:
        os.makedirs(os.path.dirname(save_path), exist_ok=True)
        
        response = requests.get(url, stream=True, timeout=300)
        response.raise_for_status()
        
        with open(save_path, 'wb') as f:
            for chunk in response.iter_content(chunk_size=8192):
                f.write(chunk)
        
        if expected_hash:
            if not self.verify_hash(save_path, expected_hash):
                os.remove(save_path)
                raise ValueError(f"Hash verification failed for {url}")
        
        return save_path
    
    def safe_load_checkpoint(self, checkpoint_path: str, map_location: str = 'cpu') -> Dict:
        class RestrictedUnpickler(pickle.Unpickler):
            def find_class(self, module, name):
                safe_modules = {
                    'torch', 'torch.nn', 'torch.optim', 'torch.cuda',
                    'torch.nn.modules', 'torch.nn.parameter', 'torch.storage',
                    'collections', 'numpy', 'builtins', '_codecs'
                }
                
                module_root = module.split('.')[0]
                if module_root not in safe_modules:
                    raise pickle.UnpicklingError(f"Unsafe module: {module}")
                
                if name in ['eval', 'exec', 'compile', '__import__', 'open']:
                    raise pickle.UnpicklingError(f"Unsafe function: {name}")
                
                return super().find_class(module, name)
        
        with open(checkpoint_path, 'rb') as f:
            checkpoint = torch.load(f, map_location=map_location, weights_only=False, pickle_module=pickle)
        
        return checkpoint
    
    def sanitize_state_dict(self, state_dict: Dict) -> Dict:
        sanitized = {}
        for key, value in state_dict.items():
            if isinstance(value, torch.Tensor):
                if torch.isnan(value).any() or torch.isinf(value).any():
                    warnings.warn(f"Found NaN or Inf in parameter {key}, skipping")
                    continue
                sanitized[key] = value
            else:
                sanitized[key] = value
        return sanitized


class ModelDownloader:
    def __init__(self, cache_dir: str = './model_cache', trusted_hashes_file: Optional[str] = None):
        self.cache_dir = Path(cache_dir)
        self.cache_dir.mkdir(parents=True, exist_ok=True)
        self.loader = SecureModelLoader(trusted_hashes_file)
        
        self.model_registry = {
            'resnet18': {
                'url': 'https://download.pytorch.org/models/resnet18-5c106cde.pth',
                'hash': '5c106cde'
            },
            'resnet50': {
                'url': 'https://download.pytorch.org/models/resnet50-19c8e357.pth',
                'hash': '19c8e357'
            }
        }
    
    def download_pretrained_model(self, model_name: str, verify_hash: bool = True) -> str:
        if model_name not in self.model_registry:
            raise ValueError(f"Unknown model: {model_name}")
        
        model_info = self.model_registry[model_name]
        url = model_info['url']
        expected_hash = model_info.get('hash') if verify_hash else None
        
        filename = url.split('/')[-1]
        save_path = self.cache_dir / filename
        
        if save_path.exists():
            if expected_hash and not self.loader.verify_hash(str(save_path), expected_hash):
                warnings.warn(f"Cached model hash mismatch, re-downloading")
                save_path.unlink()
            else:
                return str(save_path)
        
        return self.loader.download_model(url, str(save_path), expected_hash)
    
    def load_model_checkpoint(self, checkpoint_path: str, map_location: str = 'cpu') -> Dict:
        checkpoint = self.loader.safe_load_checkpoint(checkpoint_path, map_location)
        
        if 'state_dict' in checkpoint:
            checkpoint['state_dict'] = self.loader.sanitize_state_dict(checkpoint['state_dict'])
        elif isinstance(checkpoint, dict):
            checkpoint = self.loader.sanitize_state_dict(checkpoint)
        
        return checkpoint


class TransferLearningPipeline:
    def __init__(self, model: nn.Module, device: str = 'cpu'):
        self.model = model.to(device)
        self.device = device
        self.downloader = ModelDownloader()
    
    def load_pretrained_weights(self, model_name: str, strict: bool = False):
        checkpoint_path = self.downloader.download_pretrained_model(model_name)
        checkpoint = self.downloader.load_model_checkpoint(checkpoint_path, map_location=self.device)
        
        if isinstance(checkpoint, dict) and 'state_dict' in checkpoint:
            state_dict = checkpoint['state_dict']
        else:
            state_dict = checkpoint
        
        self.model.load_state_dict(state_dict, strict=strict)
    
    def freeze_layers(self, freeze_until: Optional[str] = None):
        freeze_all = freeze_until is None
        
        for name, param in self.model.named_parameters():
            if freeze_all:
                param.requires_grad = False
            elif freeze_until and freeze_until in name:
                break
            else:
                param.requires_grad = False
    
    def unfreeze_layers(self, unfreeze_from: Optional[str] = None):
        unfreeze_all = unfreeze_from is None
        start_unfreezing = unfreeze_all
        
        for name, param in self.model.named_parameters():
            if unfreeze_all:
                param.requires_grad = True
            elif unfreeze_from and unfreeze_from in name:
                start_unfreezing = True
            
            if start_unfreezing:
                param.requires_grad = True
    
    def replace_classifier(self, num_classes: int, classifier_name: str = 'fc'):
        if hasattr(self.model, classifier_name):
            old_classifier = getattr(self.model, classifier_name)
            
            if isinstance(old_classifier, nn.Linear):
                in_features = old_classifier.in_features
                new_classifier = nn.Linear(in_features, num_classes)
            elif isinstance(old_classifier, nn.Sequential):
                in_features = None
                for layer in reversed(old_classifier):
                    if isinstance(layer, nn.Linear):
                        in_features = layer.in_features
                        break
                if in_features:
                    new_classifier = nn.Linear(in_features, num_classes)
                else:
                    raise ValueError("Could not find Linear layer in classifier")
            else:
                raise ValueError(f"Unsupported classifier type: {type(old_classifier)}")
            
            setattr(self.model, classifier_name, new_classifier)
            self.model = self.model.to(self.device)
    
    def fine_tune(self, train_loader: DataLoader, val_loader: Optional[DataLoader] = None,
                  num_epochs: int = 10, learning_rate: float = 0.001,
                  optimizer_type: str = 'adam', criterion: Optional[nn.Module] = None):
        
        if criterion is None:
            criterion = nn.CrossEntropyLoss()
        
        if optimizer_type.lower() == 'adam':
            optimizer = optim.Adam(filter(lambda p: p.requires_grad, self.model.parameters()), 
                                 lr=learning_rate)
        elif optimizer_type.lower() == 'sgd':
            optimizer = optim.SGD(filter(lambda p: p.requires_grad, self.model.parameters()), 
                                lr=learning_rate, momentum=0.9)
        else:
            raise ValueError(f"Unsupported optimizer: {optimizer_type}")
        
        scheduler = optim.lr_scheduler.ReduceLROnPlateau(optimizer, mode='min', patience=2)
        
        best_val_loss = float('inf')
        training_history = {'train_loss': [], 'val_loss': [], 'train_acc': [], 'val_acc': []}
        
        for epoch in range(num_epochs):
            self.model.train()
            train_loss = 0.0
            train_correct = 0
            train_total = 0
            
            for batch_idx, (inputs, targets) in enumerate(train_loader):
                inputs, targets = inputs.to(self.device), targets.to(self.device)
                
                optimizer.zero_grad()
                outputs = self.model(inputs)
                loss = criterion(outputs, targets)
                loss.backward()
                
                torch.nn.utils.clip_grad_norm_(self.model.parameters(), max_norm=1.0)
                
                optimizer.step()
                
                train_loss += loss.item()
                _, predicted = outputs.max(1)
                train_total += targets.size(0)
                train_correct += predicted.eq(targets).sum().item()
            
            avg_train_loss = train_loss / len(train_loader)
            train_accuracy = 100. * train_correct / train_total
            
            training_history['train_loss'].append(avg_train_loss)
            training_history['train_acc'].append(train_accuracy)
            
            if val_loader:
                val_loss, val_accuracy = self.evaluate(val_loader, criterion)
                training_history['val_loss'].append(val_loss)
                training_history['val_acc'].append(val_accuracy)
                
                scheduler.step(val_loss)
                
                if val_loss < best_val_loss:
                    best_val_loss = val_loss
                
                print(f"Epoch {epoch+1}/{num_epochs} - "
                      f"Train Loss: {avg_train_loss:.4f}, Train Acc: {train_accuracy:.2f}% - "
                      f"Val Loss: {val_loss:.4f}, Val Acc: {val_accuracy:.2f}%")
            else:
                print(f"Epoch {epoch+1}/{num_epochs} - "
                      f"Train Loss: {avg_train_loss:.4f}, Train Acc: {train_accuracy:.2f}%")
        
        return training_history
    
    def evaluate(self, data_loader: DataLoader, criterion: nn.Module) -> Tuple[float, float]:
        self.model.eval()
        total_loss = 0.0
        correct = 0
        total = 0
        
        with torch.no_grad():
            for inputs, targets in data_loader:
                inputs, targets = inputs.to(self.device), targets.to(self.device)
                outputs = self.model(inputs)
                loss = criterion(outputs, targets)
                
                total_loss += loss.item()
                _, predicted = outputs.max(1)
                total += targets.size(0)
                correct += predicted.eq(targets).sum().item()
        
        avg_loss = total_loss / len(data_loader)
        accuracy = 100. * correct / total
        
        return avg_loss, accuracy
    
    def save_model(self, save_path: str, include_optimizer: bool = False, 
                   optimizer: Optional[optim.Optimizer] = None, epoch: Optional[int] = None):
        checkpoint = {
            'model_state_dict': self.model.state_dict(),
            'epoch': epoch
        }
        
        if include_optimizer and optimizer:
            checkpoint['optimizer_state_dict'] = optimizer.state_dict()
        
        torch.save(checkpoint, save_path)


class CustomDataset(Dataset):
    def __init__(self, data, labels, transform=None):
        self.data = data
        self.labels = labels
        self.transform = transform
    
    def __len__(self):
        return len(self.data)
    
    def __getitem__(self, idx):
        sample = self.data[idx]
        label = self.labels[idx]
        
        if self.transform:
            sample = self.transform(sample)
        
        return sample, label


def create_simple_model(num_classes: int = 10) -> nn.Module:
    model = nn.Sequential(
        nn.Flatten(),
        nn.Linear(784, 256),
        nn.ReLU(),
        nn.Dropout(0.3),
        nn.Linear(256, 128),
        nn.ReLU(),
        nn.Dropout(0.3),
        nn.Linear(128, num_classes)
    )
    return model


